sql:
SELECT COUNT(flight_id) AS Number_of_Delayed_Flights
FROM flight_performance
WHERE delayed = 1 AND delay_minutes > 30;

SELECT COUNT(flight_id) AS on_time_flights
FROM flight_performance
WHERE on_time_arrival = 1;

SELECT AVG(delay_minutes) AS average_delay_minutes
FROM flight_performance
WHERE delayed = 1;

SELECT flight_number, COUNT(*) AS total_flights
FROM flights
GROUP BY flight_number;

external_knowledge:
- "storm clouds that loom over the flight paths" metaphorically refers to flight delays; 
- "average time these clouds delay the journey" represents the average delay time in minutes for the flights;
- "total number of flights they've shadowed" refers to the total delayed flights;
- "names of the departure and arrival airports" are the respective airports from which and to which delayed flights take off and land.

